type AgentLeaseStatus = 'requested' | 'granted' | 'denied' | 'revoked' | 'expired';
type AgentLeaseMaterialClass = 'tool' | 'file' | 'secret' | 'pii' | 'browser' | 'worker' | 'network' | 'mutable_state' | 'mesh_peer' | 'run_budget';
type SensitiveGrantMode = 'metadata_only' | 'redacted_view' | 'derived_answer' | 'brokered_action' | 'raw_read';

interface AgentLeaseGrant {
  id: string;
  status: AgentLeaseStatus;
  holder: string;
  issuer: string;
  materialClass: AgentLeaseMaterialClass;
  resourceRefs: string[];
  operationSet: string[];
  purpose: string;
  scope: Record<string, unknown>;
  issuedAt: string;
  expiresAt: string;
  brokerRef?: string;
  proofRefs: string[];
}
